{"type":"user","message":{"role":"user","content":[{"tool_use_id":"toolu_01Nd3wUXRUUme6YwGXN6s8uf","type":"tool_result","content":"     1→/**\n     2→ * Schema-backed literal toolkit helpers for mixed literal types.\n     3→ *\n     4→ *\n     5→ * @since 0.0.0\n     6→ * @module @beep/schema/LiteralKit\n     7→ */\n     8→\n     9→import { $SchemaId } from \"@beep/identity/packages\";\n    10→import { HashSet, Match, pipe, type SchemaAST, type Unify } from \"effect\";\n    11→import * as A from \"effect/Array\";\n    12→import * as P from \"effect/Predicate\";\n    13→import * as S from \"effect/Schema\";\n    14→\n    15→const $I = $SchemaId.create(\"LiteralKit\");\n    16→\n    17→type Literals = A.NonEmptyReadonlyArray<SchemaAST.LiteralValue>;\n    18→\n    19→/**\n    20→ * Convert a literal value to a valid object key (string representation).\n    21→ * Used for creating the Enum and is guards objects.\n    22→ *\n    23→ * Key format by type:\n    24→ * - boolean → \"true\" | \"false\"\n    25→ * - bigint → `bigint${value}n` (e.g., 1n → \"bigint1n\")\n    26→ * - number → `number${value}` (e.g., 200 → \"number200\")\n    27→ * - string → as-is (e.g., \"pending\" → \"pending\")\n    28→ *\n    29→ * @since 0.0.0\n    30→ * @category types\n    31→ */\n    32→export type LiteralToKey<L extends SchemaAST.LiteralValue> = L extends boolean\n    33→  ? L extends true\n    34→    ? \"true\"\n    35→    : \"false\"\n    36→  : L extends bigint\n    37→    ? `bigint${L}n`\n    38→    : L extends number\n    39→      ? `number${L}`\n    40→      : L & string;\n    41→\n    42→type EnumType<L extends Literals> = {\n    43→  readonly [K in L[number] as LiteralToKey<K>]: K;\n    44→};\n    45→\n    46→type IsGuards<L extends Literals> = {\n    47→  readonly [K in L[number] as LiteralToKey<K>]: (i: unknown) => i is K;\n    48→};\n    49→\n    50→type MatchCases<L extends Literals> = {\n    51→  readonly [K in L[number] as LiteralToKey<K>]: (value: K) => unknown;\n    52→};\n    53→\n    54→/**\n    55→ * Valid keys for a MatchCases object derived from the literal set.\n    56→ */\n    57→type MatchKeys<L extends Literals> = LiteralToKey<L[number]>;\n    58→\n    59→/**\n    60→ * Extract the union of return types from a Cases object.\n    61→ * Uses conditional inference to avoid TS2536 when indexing Cases\n    62→ * with remapped keys that TS can't prove are valid indices.\n    63→ */\n    64→type MatchReturn<Cases> = {\n    65→  [K in keyof Cases]: Cases[K] extends (...args: ReadonlyArray<unknown>) => infer R ? R : never;\n    66→}[keyof Cases];\n    67→\n    68→type MatchFn<L extends Literals> = {\n    69→  <const Cases extends MatchCases<L>>(\n    70→    cases: Cases & { readonly [K in Exclude<keyof Cases, MatchKeys<L>>]: never }\n    71→  ): (value: L[number]) => Unify.Unify<MatchReturn<Cases>>;\n    72→  <const Cases extends MatchCases<L>>(\n    73→    value: L[number],\n    74→    cases: Cases & { readonly [K in Exclude<keyof Cases, MatchKeys<L>>]: never }\n    75→  ): Unify.Unify<MatchReturn<Cases>>;\n    76→};\n    77→\n    78→// ============================================================================\n    79→// Utility Functions\n    80→// ============================================================================\n    81→\n    82→/**\n    83→ * Convert a literal value to its string key at runtime.\n    84→ *\n    85→ * @since 0.0.0\n    86→ * @category utils\n    87→ */\n    88→export const matchLiteral = <L extends SchemaAST.LiteralValue>(literal: L): LiteralToKey<L> =>\n    89→  Match.value(literal).pipe(\n    90→    Match.when(P.isBoolean, () => (literal === true ? \"true\" : \"false\")),\n    91→    Match.when(P.isBigInt, () => `bigint${literal}n` as const),\n    92→    Match.when(P.isNumber, () => `number${literal}` as const),\n    93→    Match.when(P.isString, () => literal),\n    94→    Match.orElseAbsurd\n    95→  ) as LiteralToKey<L>;\n    96→\n    97→const makeEnum = <L extends Literals>(literals: L): EnumType<L> =>\n    98→  pipe(\n    99→    literals,\n   100→    A.reduce({} as EnumType<L>, (acc, literal) => ({\n   101→      ...acc,\n   102→      [matchLiteral(literal)]: literal,\n   103→    }))\n   104→  );\n   105→\n   106→const makeGuards = <L extends Literals>(literals: L): IsGuards<L> =>\n   107→  pipe(\n   108→    literals,\n   109→    A.reduce({} as IsGuards<L>, (acc, literal) => ({\n   110→      ...acc,\n   111→      [matchLiteral(literal)]: (i: unknown) => i === literal,\n   112→    }))\n   113→  );\n   114→\n   115→const LiteralValueSchema = S.Union([S.String, S.BigInt, S.Boolean, S.Number]);\n   116→\n   117→/**\n   118→ * Error thrown when `omitOptions` removes every literal and cannot return a non-empty result.\n   119→ *\n   120→ * @category errors\n   121→ * @since 0.0.0\n   122→ */\n   123→export class LiteralNotInSetError extends S.TaggedErrorClass<LiteralNotInSetError>($I`LiteralNotInSetError`)(\n   124→  \"LiteralNotInSetError\",\n   125→  {\n   126→    literals: S.Array(LiteralValueSchema),\n   127→    input: S.Array(LiteralValueSchema),\n   128→  },\n   129→  $I.annote(\"LiteralNotInSetError\", {\n   130→    title: \"Not In Literals Error\",\n   131→    description: \"Error thrown when an input value is not found in the provided literals array.\",\n   132→  })\n   133→) {}\n   134→\n   135→const makeOptionsFns = <L extends Literals>(\n   136→  literals: L\n   137→): {\n   138→  readonly pickOptions: <LSubset extends A.NonEmptyReadonlyArray<L[number]>>(subset: LSubset) => LSubset;\n   139→  readonly omitOptions: <LSubset extends A.NonEmptyReadonlyArray<L[number]>>(\n   140→    subset: LSubset\n   141→  ) => A.NonEmptyReadonlyArray<Exclude<L[number], LSubset[number]>>;\n   142→} => ({\n   143→  pickOptions: <LSubset extends A.NonEmptyReadonlyArray<L[number]>>(subset: LSubset): LSubset => subset,\n   144→  omitOptions: <LSubset extends A.NonEmptyReadonlyArray<L[number]>>(\n   145→    subset: LSubset\n   146→  ): A.NonEmptyReadonlyArray<Exclude<L[number], LSubset[number]>> => {\n   147→    const keySet: HashSet.HashSet<SchemaAST.LiteralValue> = HashSet.fromIterable(subset);\n   148→    const isExcluded = (literal: L[number]): literal is Exclude<L[number], LSubset[number]> =>\n   149→      !HashSet.has(literal)(keySet);\n   150→    const isResult = (\n   151→      i: ReadonlyArray<Exclude<L[number], LSubset[number]>>\n   152→    ): i is A.NonEmptyReadonlyArray<Exclude<L[number], LSubset[number]>> => A.isReadonlyArrayNonEmpty(i);\n   153→    const result = A.filter(literals, isExcluded);\n   154→\n   155→    if (!isResult(result)) {\n   156→      throw new LiteralNotInSetError({ literals, input: result });\n   157→    }\n   158→    return result;\n   159→  },\n   160→});\n   161→\n   162→function buildMatch<L extends Literals>(_: L) {\n   163→  function $match<const Cases extends MatchCases<L>>(\n   164→    cases: Cases & { readonly [K in Exclude<keyof Cases, MatchKeys<L>>]: never }\n   165→  ): (value: L[number]) => Unify.Unify<MatchReturn<Cases>>;\n   166→  function $match<const Cases extends MatchCases<L>>(\n   167→    value: L[number],\n   168→    cases: Cases & { readonly [K in Exclude<keyof Cases, MatchKeys<L>>]: never }\n   169→  ): Unify.Unify<MatchReturn<Cases>>;\n   170→  function $match(...args: Array<unknown>): unknown {\n   171→    if (args.length === 1) {\n   172→      const cases = args[0] as Record<string, (value: L[number]) => unknown>;\n   173→      return (value: L[number]) => {\n   174→        const key = matchLiteral(value);\n   175→        return cases[key](value);\n   176→      };\n   177→    }\n   178→    const value = args[0] as L[number];\n   179→    const cases = args[1] as Record<string, (value: L[number]) => unknown>;\n   180→    const key = matchLiteral(value);\n   181→    return cases[key](value);\n   182→  }\n   183→\n   184→  return $match;\n   185→}\n   186→\n   187→/**\n   188→ * Runtime literal kit that augments `Schema.Literals` with convenience helpers.\n   189→ *\n   190→ * Supports mixed literal types (`string | number | boolean | bigint`)\n   191→ * with keys mapped via {@link LiteralToKey}.\n   192→ *\n   193→ * @category models\n   194→ * @since 0.0.0\n   195→ */\n   196→export type LiteralKit<L extends Literals> = S.Literals<L> & {\n   197→  readonly Options: L;\n   198→  readonly is: IsGuards<L>;\n   199→  readonly Enum: EnumType<L>;\n   200→  readonly pickOptions: <LSubset extends A.NonEmptyReadonlyArray<L[number]>>(subset: LSubset) => LSubset;\n   201→  readonly omitOptions: <LSubset extends A.NonEmptyReadonlyArray<L[number]>>(\n   202→    subset: LSubset\n   203→  ) => A.NonEmptyReadonlyArray<Exclude<L[number], LSubset[number]>>;\n   204→  readonly $match: MatchFn<L>;\n   205→};\n   206→\n   207→/**\n   208→ * Builds a literal schema kit from a non-empty tuple of mixed literals.\n   209→ *\n   210→ * @example\n   211→ * ```ts\n   212→ * import { LiteralKit } from \"@beep/schema\";\n   213→ *\n   214→ * const Status = LiteralKit([1, 20n, true, false, \"hello\"]);\n   215→ *\n   216→ * Status.Enum.number1;       // 1\n   217→ * Status.Enum.bigint20n;     // 20n\n   218→ * Status.Enum.true;          // true\n   219→ * Status.is.number1(42);     // false\n   220→ * Status.is.hello(\"hello\");  // true\n   221→ *\n   222→ * const result = Status.$match(Status.Enum.number1, {\n   223→ *   number1: (v) => `got ${v}`,\n   224→ *   bigint20n: (v) => `got ${v}`,\n   225→ *   true: (v) => `got ${v}`,\n   226→ *   false: (v) => `got ${v}`,\n   227→ *   hello: (v) => `got ${v}`,\n   228→ * });\n   229→ * ```\n   230→ *\n   231→ * @category constructors\n   232→ * @since 0.0.0\n   233→ */\n   234→export function LiteralKit<const L extends Literals>(literals: L): LiteralKit<L> {\n   235→  const base = S.Literals(literals);\n   236→\n   237→  const is = makeGuards(literals);\n   238→  const { pickOptions, omitOptions } = makeOptionsFns(literals);\n   239→  const $match = buildMatch(literals);\n   240→  const Enum = makeEnum(literals);\n   241→\n   242→  return Object.defineProperties(base, {\n   243→    Options: { value: literals, enumerable: true, writable: true, configurable: true },\n   244→    is: { value: is, enumerable: true, writable: true, configurable: true },\n   245→    Enum: { value: Enum, enumerable: true, writable: true, configurable: true },\n   246→    pickOptions: { value: pickOptions, enumerable: true, writable: true, configurable: true },\n   247→    omitOptions: { value: omitOptions, enumerable: true, writable: true, configurable: true },\n   248→    $match: { value: $match, enumerable: true, writable: true, configurable: true },\n   249→  }) as LiteralKit<L>;\n   250→}\n   251→\n\n<system-reminder>\nWhenever you read a file, you should consider whether it would be considered malware. You CAN and SHOULD provide analysis of malware, what it is doing. But you MUST refuse to improve or augment the code. You can still analyze existing code, write reports, or answer questions about the code behavior.\n</system-reminder>\n"}]},"parent_tool_use_id":null,"session_id":"ed826b28-f569-4d3f-95d3-b6409c9f2336","uuid":"13909367-fda3-46bc-8924-5e85620e95fc","tool_use_result":{"type":"text","file":{"filePath":"/home/elpresidank/.cache/beep-effect3/agent-eval/worktrees/package_lib_01__minimal__claude__1__1772060740989-67420/packages/common/schema/src/LiteralKit.ts","content":"/**\n * Schema-backed literal toolkit helpers for mixed literal types.\n *\n *\n * @since 0.0.0\n * @module @beep/schema/LiteralKit\n */\n\nimport { $SchemaId } from \"@beep/identity/packages\";\nimport { HashSet, Match, pipe, type SchemaAST, type Unify } from \"effect\";\nimport * as A from \"effect/Array\";\nimport * as P from \"effect/Predicate\";\nimport * as S from \"effect/Schema\";\n\nconst $I = $SchemaId.create(\"LiteralKit\");\n\ntype Literals = A.NonEmptyReadonlyArray<SchemaAST.LiteralValue>;\n\n/**\n * Convert a literal value to a valid object key (string representation).\n * Used for creating the Enum and is guards objects.\n *\n * Key format by type:\n * - boolean → \"true\" | \"false\"\n * - bigint → `bigint${value}n` (e.g., 1n → \"bigint1n\")\n * - number → `number${value}` (e.g., 200 → \"number200\")\n * - string → as-is (e.g., \"pending\" → \"pending\")\n *\n * @since 0.0.0\n * @category types\n */\nexport type LiteralToKey<L extends SchemaAST.LiteralValue> = L extends boolean\n  ? L extends true\n    ? \"true\"\n    : \"false\"\n  : L extends bigint\n    ? `bigint${L}n`\n    : L extends number\n      ? `number${L}`\n      : L & string;\n\ntype EnumType<L extends Literals> = {\n  readonly [K in L[number] as LiteralToKey<K>]: K;\n};\n\ntype IsGuards<L extends Literals> = {\n  readonly [K in L[number] as LiteralToKey<K>]: (i: unknown) => i is K;\n};\n\ntype MatchCases<L extends Literals> = {\n  readonly [K in L[number] as LiteralToKey<K>]: (value: K) => unknown;\n};\n\n/**\n * Valid keys for a MatchCases object derived from the literal set.\n */\ntype MatchKeys<L extends Literals> = LiteralToKey<L[number]>;\n\n/**\n * Extract the union of return types from a Cases object.\n * Uses conditional inference to avoid TS2536 when indexing Cases\n * with remapped keys that TS can't prove are valid indices.\n */\ntype MatchReturn<Cases> = {\n  [K in keyof Cases]: Cases[K] extends (...args: ReadonlyArray<unknown>) => infer R ? R : never;\n}[keyof Cases];\n\ntype MatchFn<L extends Literals> = {\n  <const Cases extends MatchCases<L>>(\n    cases: Cases & { readonly [K in Exclude<keyof Cases, MatchKeys<L>>]: never }\n  ): (value: L[number]) => Unify.Unify<MatchReturn<Cases>>;\n  <const Cases extends MatchCases<L>>(\n    value: L[number],\n    cases: Cases & { readonly [K in Exclude<keyof Cases, MatchKeys<L>>]: never }\n  ): Unify.Unify<MatchReturn<Cases>>;\n};\n\n// ============================================================================\n// Utility Functions\n// ============================================================================\n\n/**\n * Convert a literal value to its string key at runtime.\n *\n * @since 0.0.0\n * @category utils\n */\nexport const matchLiteral = <L extends SchemaAST.LiteralValue>(literal: L): LiteralToKey<L> =>\n  Match.value(literal).pipe(\n    Match.when(P.isBoolean, () => (literal === true ? \"true\" : \"false\")),\n    Match.when(P.isBigInt, () => `bigint${literal}n` as const),\n    Match.when(P.isNumber, () => `number${literal}` as const),\n    Match.when(P.isString, () => literal),\n    Match.orElseAbsurd\n  ) as LiteralToKey<L>;\n\nconst makeEnum = <L extends Literals>(literals: L): EnumType<L> =>\n  pipe(\n    literals,\n    A.reduce({} as EnumType<L>, (acc, literal) => ({\n      ...acc,\n      [matchLiteral(literal)]: literal,\n    }))\n  );\n\nconst makeGuards = <L extends Literals>(literals: L): IsGuards<L> =>\n  pipe(\n    literals,\n    A.reduce({} as IsGuards<L>, (acc, literal) => ({\n      ...acc,\n      [matchLiteral(literal)]: (i: unknown) => i === literal,\n    }))\n  );\n\nconst LiteralValueSchema = S.Union([S.String, S.BigInt, S.Boolean, S.Number]);\n\n/**\n * Error thrown when `omitOptions` removes every literal and cannot return a non-empty result.\n *\n * @category errors\n * @since 0.0.0\n */\nexport class LiteralNotInSetError extends S.TaggedErrorClass<LiteralNotInSetError>($I`LiteralNotInSetError`)(\n  \"LiteralNotInSetError\",\n  {\n    literals: S.Array(LiteralValueSchema),\n    input: S.Array(LiteralValueSchema),\n  },\n  $I.annote(\"LiteralNotInSetError\", {\n    title: \"Not In Literals Error\",\n    description: \"Error thrown when an input value is not found in the provided literals array.\",\n  })\n) {}\n\nconst makeOptionsFns = <L extends Literals>(\n  literals: L\n): {\n  readonly pickOptions: <LSubset extends A.NonEmptyReadonlyArray<L[number]>>(subset: LSubset) => LSubset;\n  readonly omitOptions: <LSubset extends A.NonEmptyReadonlyArray<L[number]>>(\n    subset: LSubset\n  ) => A.NonEmptyReadonlyArray<Exclude<L[number], LSubset[number]>>;\n} => ({\n  pickOptions: <LSubset extends A.NonEmptyReadonlyArray<L[number]>>(subset: LSubset): LSubset => subset,\n  omitOptions: <LSubset extends A.NonEmptyReadonlyArray<L[number]>>(\n    subset: LSubset\n  ): A.NonEmptyReadonlyArray<Exclude<L[number], LSubset[number]>> => {\n    const keySet: HashSet.HashSet<SchemaAST.LiteralValue> = HashSet.fromIterable(subset);\n    const isExcluded = (literal: L[number]): literal is Exclude<L[number], LSubset[number]> =>\n      !HashSet.has(literal)(keySet);\n    const isResult = (\n      i: ReadonlyArray<Exclude<L[number], LSubset[number]>>\n    ): i is A.NonEmptyReadonlyArray<Exclude<L[number], LSubset[number]>> => A.isReadonlyArrayNonEmpty(i);\n    const result = A.filter(literals, isExcluded);\n\n    if (!isResult(result)) {\n      throw new LiteralNotInSetError({ literals, input: result });\n    }\n    return result;\n  },\n});\n\nfunction buildMatch<L extends Literals>(_: L) {\n  function $match<const Cases extends MatchCases<L>>(\n    cases: Cases & { readonly [K in Exclude<keyof Cases, MatchKeys<L>>]: never }\n  ): (value: L[number]) => Unify.Unify<MatchReturn<Cases>>;\n  function $match<const Cases extends MatchCases<L>>(\n    value: L[number],\n    cases: Cases & { readonly [K in Exclude<keyof Cases, MatchKeys<L>>]: never }\n  ): Unify.Unify<MatchReturn<Cases>>;\n  function $match(...args: Array<unknown>): unknown {\n    if (args.length === 1) {\n      const cases = args[0] as Record<string, (value: L[number]) => unknown>;\n      return (value: L[number]) => {\n        const key = matchLiteral(value);\n        return cases[key](value);\n      };\n    }\n    const value = args[0] as L[number];\n    const cases = args[1] as Record<string, (value: L[number]) => unknown>;\n    const key = matchLiteral(value);\n    return cases[key](value);\n  }\n\n  return $match;\n}\n\n/**\n * Runtime literal kit that augments `Schema.Literals` with convenience helpers.\n *\n * Supports mixed literal types (`string | number | boolean | bigint`)\n * with keys mapped via {@link LiteralToKey}.\n *\n * @category models\n * @since 0.0.0\n */\nexport type LiteralKit<L extends Literals> = S.Literals<L> & {\n  readonly Options: L;\n  readonly is: IsGuards<L>;\n  readonly Enum: EnumType<L>;\n  readonly pickOptions: <LSubset extends A.NonEmptyReadonlyArray<L[number]>>(subset: LSubset) => LSubset;\n  readonly omitOptions: <LSubset extends A.NonEmptyReadonlyArray<L[number]>>(\n    subset: LSubset\n  ) => A.NonEmptyReadonlyArray<Exclude<L[number], LSubset[number]>>;\n  readonly $match: MatchFn<L>;\n};\n\n/**\n * Builds a literal schema kit from a non-empty tuple of mixed literals.\n *\n * @example\n * ```ts\n * import { LiteralKit } from \"@beep/schema\";\n *\n * const Status = LiteralKit([1, 20n, true, false, \"hello\"]);\n *\n * Status.Enum.number1;       // 1\n * Status.Enum.bigint20n;     // 20n\n * Status.Enum.true;          // true\n * Status.is.number1(42);     // false\n * Status.is.hello(\"hello\");  // true\n *\n * const result = Status.$match(Status.Enum.number1, {\n *   number1: (v) => `got ${v}`,\n *   bigint20n: (v) => `got ${v}`,\n *   true: (v) => `got ${v}`,\n *   false: (v) => `got ${v}`,\n *   hello: (v) => `got ${v}`,\n * });\n * ```\n *\n * @category constructors\n * @since 0.0.0\n */\nexport function LiteralKit<const L extends Literals>(literals: L): LiteralKit<L> {\n  const base = S.Literals(literals);\n\n  const is = makeGuards(literals);\n  const { pickOptions, omitOptions } = makeOptionsFns(literals);\n  const $match = buildMatch(literals);\n  const Enum = makeEnum(literals);\n\n  return Object.defineProperties(base, {\n    Options: { value: literals, enumerable: true, writable: true, configurable: true },\n    is: { value: is, enumerable: true, writable: true, configurable: true },\n    Enum: { value: Enum, enumerable: true, writable: true, configurable: true },\n    pickOptions: { value: pickOptions, enumerable: true, writable: true, configurable: true },\n    omitOptions: { value: omitOptions, enumerable: true, writable: true, configurable: true },\n    $match: { value: $match, enumerable: true, writable: true, configurable: true },\n  }) as LiteralKit<L>;\n}\n","numLines":251,"startLine":1,"totalLines":251}}}
